  cwd: process.cwd(),
  stdio: "inherit",
  env: {
    ...process.env,
    PORT: port
  }
});

try {
  await waitForHealth(`http://${host}:${port}/api/health`);
} finally {
  child.kill("SIGTERM");
}

import "dotenv/config";

